mapper.select:
select id, actor_id as actorId, module, action, method, path, status_code as statusCode,
       request_id as requestId, summary, create_time as createTime
from admin_operation_log
where 1 = 1

    and module = #{module}


    and action = #{action}

order by create_time desc, id desc
limit #{pageSize} offset #{offset}

select count(1)
from admin_operation_log
where 1 = 1

    and module = #{module}


    and action = #{action}
